import{_ as a,o as n,c as s,a6 as t}from"./chunks/framework.BBdhcoHf.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),i={name:"guide/index.md"};function r(o,e,l,p,c,h){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to “Table of Contents”">​</a></h2><ul><li><a href="#introduction">Introduction</a></li><li><a href="#use-cases">Use cases</a></li><li><a href="#performance">Performance</a></li><li><a href="#the-framework-name">The framework name</a></li><li><a href="#development-status">Development status</a></li><li><a href="#project-objective">Project objective</a></li></ul><p>I have a dream: high-performance, highly scalable, and very fast applications written in PHP; and since there are now fibers in the core of PHP, I feel that the time is right for this dream to come true.</p><p>Phenix is a web framework built on pure PHP, without external extensions, based on the <a href="https://amphp.org/" target="_blank" rel="noreferrer">Amphp</a> ecosystem, which provides non-blocking operations, asynchronism, and parallel code execution natively. It runs in the PHP SAPI CLI and on its own server; it is simply powerful.</p><p>Phenix does not try to compete with other frameworks like Laravel. Laravel is powerful and has a different approach. On the contrary, Phenix is inspired by the simplicity and elegance of Laravel; the philosophy of a beautiful syntax is maintained.</p><p>The goal of Phenix is to be a tool for the development of modern and high-concurrency web applications.</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use cases”">​</a></h2><p>Since Phenix has its own web server framework, you can use it to build web services like:</p><ul><li>RESTful API services</li><li>Game servers</li><li>IoT</li><li>Chat systems</li><li>Headless CMS platforms</li><li>Microservices</li><li>Real-time web services</li></ul><p>If you wanted to compare it with other frameworks, then think about ExpressJS.</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to “Performance”">​</a></h2><p>One of the most interesting aspects when trying to get to know a new framework is performance, which is why I present a performance test made with Apache Bench version 2.3; for this test, XDebug was disabled:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ab -n100000 -c50 -k http://127.0.0.1:1337/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Concurrency Level:      50</span></span>
<span class="line"><span>Time taken for tests:   14.008 seconds</span></span>
<span class="line"><span>Complete requests:      100000</span></span>
<span class="line"><span>Failed requests:        0</span></span>
<span class="line"><span>Keep-Alive requests:    0</span></span>
<span class="line"><span>Total transferred:      11500000 bytes</span></span>
<span class="line"><span>HTML transferred:       1400000 bytes</span></span>
<span class="line"><span>Requests per second:    7138.61 [#/sec] (mean)</span></span>
<span class="line"><span>Time per request:       7.004 [ms] (mean)</span></span>
<span class="line"><span>Time per request:       0.140 [ms] (mean, across all concurrent requests)</span></span>
<span class="line"><span>Transfer rate:          801.70 [Kbytes/sec] received</span></span></code></pre></div><h2 id="the-framework-name" tabindex="-1">The framework name <a class="header-anchor" href="#the-framework-name" aria-label="Permalink to “The framework name”">​</a></h2><p>The name Phenix comes from the union between PHP and Phoenix (PHP + Phoenix = Phenix). Basically, I try to highlight that PHP will never die; it simply resurfaces better and better again and again. Each time it is reborn, it is much better than its previous version.</p><h2 id="development-status" tabindex="-1">Development status <a class="header-anchor" href="#development-status" aria-label="Permalink to “Development status”">​</a></h2><p>Phenix is in active development, <strong>not production ready</strong>. I hope to release the first stable version very soon.</p><h2 id="project-objective" tabindex="-1">Project objective <a class="header-anchor" href="#project-objective" aria-label="Permalink to “Project objective”">​</a></h2><p>All basic features built constitute a minimum viable product (MVP), with the objective to obtain the PHP community&#39;s support and continue with the framework development. The opportunity offered by the Amphp ecosystem has a lot of potential: asynchronous code, parallelism, and concurrency in PHP.</p><p>Let&#39;s create amazing applications with the full potential of PHP.</p>`,21)])])}const f=a(i,[["render",r]]);export{m as __pageData,f as default};
